package main
import "fmt"
import "math"
func main() {
    var n int
    fmt.Scan(&n)
    jogadores := make([]int, 0, n)
    diferencas := make([]float64, 0, n)

    for i := range n{
        var pa, pb float64
        fmt.Scan(&pa, &pb)
        diferenca := math.Abs(pa-pb)
        diferencas = append(diferencas, diferenca)
        if (diferenca < 10){
            jogadores = append(jogadores, i)
        }
    }

    fmt.Print(diferencas)
}
